sql.where:
and warehouse_id = #{wareHouseId}

    and id = #{ew.id}


    and lock_key = #{ew.lockKey}


    and owner_type = #{ew.ownerType}


    and owner_id = #{ew.ownerId}


    and status = #{ew.status}

choose.when:
insert into wcs_resource_lock (warehouse_id, lock_key, owner_type, owner_id, status, expire_at, created_at, updated_at)
select #{warehouseId}, #{lockKey}, #{ownerType}, #{ownerId}, #{status}, #{expireAt}, GETDATE(), GETDATE()
where not exists (
    select 1 from wcs_resource_lock where warehouse_id = #{warehouseId} and lock_key = #{lockKey}
)

choose.otherwise:
insert into wcs_resource_lock (warehouse_id, lock_key, owner_type, owner_id, status, expire_at, created_at, updated_at)
select #{warehouseId}, #{lockKey}, #{ownerType}, #{ownerId}, #{status}, #{expireAt}, now(), now()
where not exists (
    select 1 from wcs_resource_lock where warehouse_id = #{warehouseId} and lock_key = #{lockKey}
)

mapper.update:
update wcs_resource_lock

    status = 'HELD',
    expire_at = #{expireAt},

        updated_at = GETDATE()
        updated_at = now()


where warehouse_id = #{wareHouseId}
  and lock_key = #{lockKey}
  and owner_type = #{ownerType}
  and owner_id = #{ownerId}
  and status = 'HELD'
  and (expire_at is null or expire_at > #{now})

update wcs_resource_lock

    status = 'RELEASED',

        updated_at = GETDATE()
        updated_at = now()


where warehouse_id = #{wareHouseId}
  and lock_key = #{lockKey}
  and owner_type = #{ownerType}
  and owner_id = #{ownerId}
  and status = 'HELD'

update wcs_resource_lock

    status = 'RELEASED',

        updated_at = GETDATE()
        updated_at = now()


where warehouse_id = #{wareHouseId}
  and lock_key = #{lockKey}
